import{_ as a,c as i,o as t,ah as s}from"./chunks/framework.Cnj7lwEt.js";const u=JSON.parse('{"title":"GitHub Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"en/github-guide.md","filePath":"en/github-guide.md"}'),r={name:"en/github-guide.md"};function o(l,e,n,h,c,d){return t(),i("div",null,e[0]||(e[0]=[s(`<h1 id="github-usage-guide" tabindex="-1">GitHub Usage Guide <a class="header-anchor" href="#github-usage-guide" aria-label="Permalink to “GitHub Usage Guide”">​</a></h1><h2 id="_01-1-introduction" tabindex="-1">01.1- Introduction <a class="header-anchor" href="#_01-1-introduction" aria-label="Permalink to “01.1- Introduction”">​</a></h2><p>GitHub is the world&#39;s largest code hosting platform, providing developers with powerful version control, collaborative development, and project management features.</p><h2 id="_01-2-basic-concepts" tabindex="-1">01.2- Basic Concepts <a class="header-anchor" href="#_01-2-basic-concepts" aria-label="Permalink to “01.2- Basic Concepts”">​</a></h2><h3 id="_01-21-repository" tabindex="-1">01.21- Repository <a class="header-anchor" href="#_01-21-repository" aria-label="Permalink to “01.21- Repository”">​</a></h3><p>A repository is the storage space for a project, containing all files, folders, and revision history for each file.</p><h3 id="_01-22-branch" tabindex="-1">01.22- Branch <a class="header-anchor" href="#_01-22-branch" aria-label="Permalink to “01.22- Branch”">​</a></h3><p>Branches allow you to develop new features or fix issues without affecting the main branch.</p><h3 id="_01-23-commit" tabindex="-1">01.23- Commit <a class="header-anchor" href="#_01-23-commit" aria-label="Permalink to “01.23- Commit”">​</a></h3><p>A commit is a record of changes made to files, with a unique ID generated for each commit.</p><h3 id="_01-24-pull-request" tabindex="-1">01.24- Pull Request <a class="header-anchor" href="#_01-24-pull-request" aria-label="Permalink to “01.24- Pull Request”">​</a></h3><p>A Pull Request is a request to merge your changes into the main branch, facilitating code review and discussion.</p><h2 id="_01-3-quick-start" tabindex="-1">01.3- Quick Start <a class="header-anchor" href="#_01-3-quick-start" aria-label="Permalink to “01.3- Quick Start”">​</a></h2><h3 id="_01-31-create-an-account" tabindex="-1">01.31- Create an Account <a class="header-anchor" href="#_01-31-create-an-account" aria-label="Permalink to “01.31- Create an Account”">​</a></h3><p>Visit <a href="https://github.com" target="_blank" rel="noreferrer">GitHub Official Website</a> to register an account.</p><h3 id="_01-32-create-a-repository" tabindex="-1">01.32- Create a Repository <a class="header-anchor" href="#_01-32-create-a-repository" aria-label="Permalink to “01.32- Create a Repository”">​</a></h3><ol><li>Click the &quot;+&quot; button in the upper right corner</li><li>Select &quot;New repository&quot;</li><li>Fill in the repository name and description</li><li>Choose public or private</li><li>Click &quot;Create repository&quot;</li></ol><h3 id="_01-33-clone-repository" tabindex="-1">01.33- Clone Repository <a class="header-anchor" href="#_01-33-clone-repository" aria-label="Permalink to “01.33- Clone Repository”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://github.com/username/repository.git</span></span></code></pre></div><h3 id="_01-34-create-branch" tabindex="-1">01.34- Create Branch <a class="header-anchor" href="#_01-34-create-branch" aria-label="Permalink to “01.34- Create Branch”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -b</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-35-commit-changes" tabindex="-1">01.35- Commit Changes <a class="header-anchor" href="#_01-35-commit-changes" aria-label="Permalink to “01.35- Commit Changes”">​</a></h3><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Add new feature&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature-branch</span></span></code></pre></div><h3 id="_01-36-create-pull-request" tabindex="-1">01.36- Create Pull Request <a class="header-anchor" href="#_01-36-create-pull-request" aria-label="Permalink to “01.36- Create Pull Request”">​</a></h3><p>Create a Pull Request on the GitHub web page and wait for review and merge.</p><h2 id="_01-4-common-operations" tabindex="-1">01.4- Common Operations <a class="header-anchor" href="#_01-4-common-operations" aria-label="Permalink to “01.4- Common Operations”">​</a></h2><h3 id="_01-41-fork-project" tabindex="-1">01.41- Fork Project <a class="header-anchor" href="#_01-41-fork-project" aria-label="Permalink to “01.41- Fork Project”">​</a></h3><p>Fork allows you to copy someone else&#39;s project to your own account for modification.</p><h3 id="_01-42-star-project" tabindex="-1">01.42- Star Project <a class="header-anchor" href="#_01-42-star-project" aria-label="Permalink to “01.42- Star Project”">​</a></h3><p>Star indicates you like the project, making it easy to find later.</p><h3 id="_01-43-watch-project" tabindex="-1">01.43- Watch Project <a class="header-anchor" href="#_01-43-watch-project" aria-label="Permalink to “01.43- Watch Project”">​</a></h3><p>Watch allows you to receive update notifications for the project.</p><h3 id="_01-44-issues" tabindex="-1">01.44- Issues <a class="header-anchor" href="#_01-44-issues" aria-label="Permalink to “01.44- Issues”">​</a></h3><p>Issues are used to report problems, request features, or discuss ideas.</p><h2 id="_01-5-best-practices" tabindex="-1">01.5- Best Practices <a class="header-anchor" href="#_01-5-best-practices" aria-label="Permalink to “01.5- Best Practices”">​</a></h2><ol><li><strong>Write clear commit messages</strong> - Let others understand the purpose of each commit</li><li><strong>Use branches for development</strong> - Don&#39;t develop directly on the main branch</li><li><strong>Sync regularly</strong> - Keep local repository in sync with remote repository</li><li><strong>Code review</strong> - Conduct code reviews through Pull Requests</li><li><strong>Complete documentation</strong> - Add README and necessary documentation for the project</li></ol><h2 id="_01-6-related-resources" tabindex="-1">01.6- Related Resources <a class="header-anchor" href="#_01-6-related-resources" aria-label="Permalink to “01.6- Related Resources”">​</a></h2><ul><li><a href="https://docs.github.com" target="_blank" rel="noreferrer">GitHub Official Documentation</a></li><li><a href="/en/91git.html">Git Basics Tutorial</a></li><li><a href="/en/全部资源概述.html">All Resources Overview</a></li></ul>`,38)]))}const k=a(r,[["render",o]]);export{u as __pageData,k as default};
